// Matrice des distances en km (long[,] -- troncature int, comme Python int(distances[i,j])).
static long[,] ComputeDistanceMatrix(SportsLeague league)
{
    int n = league.NTeams;
    var d = new long[n, n];
    for (int i = 0; i < n; i++)
        for (int j = i + 1; j < n; j++)
        {
            long dist = (long)league.Distance(league.Teams[i], league.Teams[j]);
            d[i, j] = dist;
            d[j, i] = dist;
        }
    return d;
}

