// Derbys : paires de villes a moins de threshold km.
static List<(int a, int b)> FindDerbies(SportsLeague league, long[,] distances, double thresholdKm = 200)
{
    var derbies = new List<(int, int)>();
    int n = league.NTeams;
    for (int i = 0; i < n; i++)
        for (int j = i + 1; j < n; j++)
            if (distances[i, j] <= thresholdKm)
                derbies.Add((i, j));
    return derbies;
}

