long _solCount;
void EnumerateAll(int[] queens, bool[] placed, int col, int n) {
    if (col == n) { _solCount++; return; }
    for (int row = 0; row < n; row++) {
        if (IsSafe(queens, col, row, placed)) {
            queens[col] = row; placed[col] = true;
            EnumerateAll(queens, placed, col + 1, n);
            placed[col] = false;
        }
    }
}

