Console.WriteLine("Benchmark Minimax vs Alpha-Beta (plateau vide) :");
Console.WriteLine();
Console.WriteLine($"{"Depth",-6} {"MM nodes",-12} {"AB nodes",-12} {"Ratio AB/MM",-12} {"MM (ms)",-10} {"AB (ms)",-10}");
